INSERT INTO `fihl_podcstvideo` (`sno`, `videoID`, `podcast_id`, `title`, `category`, `image`, `image_path`, `maxresimage`, `subcategory`, `description`, `keyword`, `duration`, `podcast_type`, `podcast_link`, `pod_lang`, `total_comment`, `total_votes`, `total_value`, `views`, `status`, `create_date`, `created_at`, `updated_at`, `fbshare`, `twittershare`, `linkedinshare`, `whasupshare`) VALUES
(694, 'GXbyzbEoIsc', NULL, 'Dinesh Rai at Small Business Congress 2010 - Podium', 32, '', NULL, '', 0, 'SMALL BUSINESS CONGRESS 2010', 'business congress small entrepreneur ', '1.36', 'V', NULL, 'en', 0, 0, 0, 2165, 'A', '2012-11-21 16:08:58', NULL, NULL, 0, 0, 0, 0),
(695, 'tgU0L_HakAI', NULL, 'Buy or Sell your business - Gaurav Marya', 3, '', NULL, '', 0, 'The first business that Gaurav started was a career counseling company. He was then a student in an engineering college. He never really completed his degree. The first business consulting he did was when he was 25 years old. He has always loved this aspect of the business. Gaurav is widely admired for his non-conformist operating style, direct and to-the-point style of rendering managerial advice, his intelligent interventions and vigorous marketing tactics and strategy. Over the years Gaurav has provided consulting and advisory services to over twenty five thousand budding entrepreneurs with a focus on helping them select and meet the challenges of start-up businesses. He has been consulted by over 500 large and small corporations in making informed decisions about their business growth including Gitanjali Group, Emami, Videocon, Landmark Group, Tata Steel, Unilever India, Levis, 3M, HP, ITC, TVS and Mahindra Retail. He has assisted more than 50 international companies enter the Indian market.\r\n\r\nGaurav considers his greatest achievements to be his sustained engagements with small and medium enterprises that have grown into big entities. He derives immense satisfaction from being part of hundreds of success stories.', 'Franchise Entrepreneur Business Innovation ', '0.53', 'V', NULL, 'en', 0, 0, 0, 7634, 'A', '2012-11-21 16:11:18', NULL, NULL, 0, 0, 0, 0),
(1165, 'WS69a312iME', NULL, 'Amit Gupta, CEO S.Chand speaking at Indian Education Congress 2013 ', 28, '', NULL, '', 0, 'Indian Education Congress 2013 presented by Amity University and Indian Education Awards 2013 organised by S.Chand Group and Event organised by Franchise India', 'franchise, business, education, school, college, S Chand, Amity, ', '7.51', 'V', NULL, 'en', 0, 0, 0, 579, 'D', '2013-05-14 15:04:04', NULL, NULL, 0, 0, 0, 0),
(672, 'm_Hzwf9-Y48', NULL, 'MSME', 2, '', NULL, '', 0, 'MSME', 'franchise business ', '6.18', 'V', NULL, 'en', 1, 1, 1, 344, 'D', '2012-11-19 17:04:54', NULL, NULL, 0, 0, 0, 0),
(673, '2k_HILwTbvg', NULL, 'Franchise India Awards 2012', 34, '', NULL, '', 0, 'Franchise Awards 2012 are India\\\'s Topmost Honour in Franchising. Benchmarking excellence, the Awards celebrated and acknowledged contribution to one of India\\\'s most dynamic industries. The winners were those organisations that have shown outstanding business acumen, passion and achievement of franchise businesses and thus achieved sustainable growth across India. They were judged by an independent panel of experts and supported by the Indian Franchise Association (IFA) & Entrepreneur India Advisors. Franchisors, Franchisees, Master Franchisees and Entrepreneurs all over India had applied for the Awards considered to be the industry\\\'s top accolade.rnStar Retailer Awards is the only Awards of its kind which celebrates the best in Indian retailing. It is a singular platform for everyone from independent entrepreneurial retailers to the largest supermarket groups. These Awards celebrated the outstanding achievements across the retail fraternity. rnFranchise India Awards 2012 and Star Retailer Awards are the most credible and prestigious received. Taking the commitments forward, the awards this year acknowledged the best performances in the industry in various categories.', 'franchise business entrepreneur ', '11.32', 'V', NULL, 'en', 2, 2, 5, 4213, 'A', '2012-11-21 15:17:14', NULL, NULL, 0, 0, 0, 0),
(674, 'QdBBunJj_bI', NULL, 'Mapping Consumption Trends: An Aware Consumer Base', 27, '', NULL, '', 0, 'The Salon Congress 2012 is presented by Franchise India and UTV Bloomberg with Entrepreneur India Advisors as the knowledge partners and Indian Franchise Association (IFA) as supporting partners. It is a first time projection by Franchise India to conduct Salon Congress that will take note of the robust growth in the salon industry and in lieu of matching up with the international counterparts to come together and deliberate on the pertinent points of getting finances, retaining skilled personnel, bringing in standardisation in processes, creating quality consistency and more through the course of this two day comprehensive conference. The show brought forward a great networking opportunity that aims to strengthen industry connections.\\r\\nIndian Salon Congress 2012, a two day conference brought together industry veterans to interact and draw attention to best practices and promote innovation to capture consumer interest that will help grow the beauty services sector. The Expo 2012 will be a showcase and branding opportunity for your product or services operating in the beauty services segment, connecting with suppliers and other allied industries. Indian Salon Awards 2012 acknowledged contribution of market leaders and innovators from the beauty services industry.', 'franchise entrepreneur salon congress business ', '7.01', 'V', NULL, 'en', 1, 1, 2, 7230, 'A', '2012-11-21 15:32:13', NULL, NULL, 0, 0, 0, 0),
(675, '7t07CTbK99U', NULL, 'Salon Awards 2012', 34, '', NULL, '', 0, 'The Indian Salon Congress 2012, a 2-day conference, proved to be a collaborative platform for industry veterans to interact and highlight the best practices and to boost innovation to capture consumer interest that will assist to grow the beauty services sector. The best takeaways of the show was on insights into the personal care market and trends for 2012; building wide consumer base and map consumption trends; Business Strategies to integrate multiple servicesâ€“hair, nail, skin and day spa and many more.rn', 'franchise business entrepreneur ', '6.58', 'V', NULL, 'en', 1, 1, 2, 5106, 'A', '2012-11-21 15:33:59', NULL, NULL, 0, 0, 0, 0),
(676, '3MeP-bp5gPk', NULL, 'The emerging Salon Industry of India ', 27, '', NULL, '', 0, 'Salon Industry of India', 'Franchise Entrepreneur Business Innovation ', '10.43', 'V', NULL, 'en', 1, 1, 2, 1825, 'A', '2012-11-21 15:36:11', NULL, NULL, 0, 0, 0, 0),
