(718, '6jzLS6PHDtI', NULL, 'Siddharth Lal at Indian Restaurant Congress 2012', 31, '', NULL, '', 0, 'Indian Restaurant Congress 2012\r\n\r\nIndia`s Biggest National Restaurant forum in its 2nd edition focusing all the Restaurant professionals, Owners , Operators and stake holders from Restaurant industry to have a deliberate discussion on the growth of Restaurant Business in India. To discuss on the real time challenges ( in terms of Operation and financials ), imbibing best industry practices, Restaurant Franchising Know how, Networking with the industry people and to give recognition.\r\n\r\n\r\nThe Indian Restaurant Congress brought together key representatives from the food service industry, trade bodies and associations, design professionals, product development companies, manufacturers, policy makers, investment groups and other stakeholders from the restaurant supplies and food industry.', 'Restaurant, business, congress, food, awards, eat out, entrepreneur, cuisine, 2012,', '4.32', 'V', NULL, 'en', 1, 1, 5, 6464, 'A', '2012-11-23 11:43:11', NULL, NULL, 0, 0, 0, 0),
(53, 'y4v7eqGASG8', NULL, 'Opportunity to grow ', 1, '', NULL, '', 0, 'Channelplay is one of the leading retail marketing companies which helps brands to capitalize on this opportunity and is poised for strong growth in the future.', 'Franchise Business Entrepreneur Retail Business Opportunity ', '2:01', 'V', NULL, 'en', 0, 0, 0, 2506, 'A', '2011-04-25 00:54:10', NULL, NULL, 0, 0, 0, 0),
(54, 't0sZlf2bXxM', NULL, 'Leading sanitary ware in India', 1, '', NULL, '', 0, 'HSIL was the first company in India to manufacture Vitreous China Sanitary ware and has maintained its market leadership through consistent product quality and constant innovations.', 'Franchise Business Entrepreneur Retail Business Opportunity', '1:53', 'V', NULL, 'en', 1, 1, 3, 2853, 'A', '2011-04-25 00:55:29', NULL, NULL, 0, 0, 0, 0),
(55, 'tlDTH7O0iQ0', NULL, 'Designing and developing ', 1, '', NULL, '', 0, 'Herman Miller works for a better world around you by designing and developing award-winning furniture. Company named Herman Miller among the \\\"Most Innovative\\\" in 2010.', 'Franchise Business Entrepreneur Retail Business Opportunity', '1:54', 'V', NULL, 'en', 1, 1, 2, 247, 'D', '2011-04-25 00:56:38', NULL, NULL, 0, 0, 0, 0),
(56, 'HkA-b4wlj3U', NULL, 'Retail plans ', 30, '', NULL, '', 0, 'Bhaskar Bhat, MD , Titan industries shares his views about the company\\\'s retail plans and the kind of watches that would conquer the Indian market in the next 2 years.', 'Franchise Business Entrepreneur Retail Business Opportunity', '1:51', 'V', NULL, 'en', 0, 0, 0, 2734, 'A', '2011-04-25 00:58:29', NULL, NULL, 0, 0, 0, 0),
(57, 'EUcKm44EWP0', NULL, 'International customer experience', 1, '', NULL, '', 0, 'Bringing international customer experience and world class products to Indian customers without compromising on quality.', 'Satya Narayanan\\\'s exclusive interview to Franchise India at the 9th International Franchise and Retail Show. An alumni of St. Stephen\\\'s College and IIM, Bangalore he soon followed his passion, that of education and entrepreneurship. 1995, saw the launch of Career Launcher, with one goal in mind -- to enable individuals realize their potential and make their career dreams come true. A certified Crestcom and NTL trainer who has trained corporate leaders besides thousands of students, teachers and corporate executives. His entrepreneurial zeal and conviction in his dreams were recently acknowledged by Dell where he was featured in their \\\'Take Your Own Path\\\' Campaign.', '2.02', 'V', NULL, 'en', 1, 1, 3, 1953, 'A', '2011-05-03 02:40:15', NULL, NULL, 0, 0, 0, 0),
(59, 'GGkSBiHPZcA', NULL, 'Elvy\'s brand recognition ', 1, '', NULL, '', 0, 'Elvy speaks of exclusivity; style and quality which makes its brand recognition soar high. ', 'Franchise Business Entrepreneur Retail Business Opportunity brand ', '2.03', 'V', NULL, 'en', 0, 0, 0, 2060, 'A', '2011-05-05 04:37:29', NULL, NULL, 0, 0, 0, 0),
(60, 'ktZO0pQeh44', NULL, 'Documenting success solutions', 28, '', NULL, '', 0, 'Credibility around the education system in India is very poor. There is no verification system. There is no kind of certification.', 'Credibility, Certification', '2:34', 'V', NULL, 'en', 5, 5, 21, 2559, 'A', '2011-05-20 02:58:08', NULL, NULL, 0, 0, 0, 0),
(61, 'afxQ_ZivQj0', NULL, 'Education industry needs a metrical change', 28, '', NULL, '', 0, 'Speaking on the Indian Education Congress of 2011, organized by Franchise India and Zee Business, Barry states some of the best and the worst times he had in his life was at the course of education. The two day session he hopes to be fruitful one wherein words are expected to be transformed into action, as that matters the most. Barry affirmed the education sector is one which is a complicated one and requires multiple stack holders and cross collaboration. Industry example was cited wherein how the USA was once the ruling head of education, however that was 50 years ago and ever since then it has been in its decline. He further spoke about the various aspects and ramification of education; education being divided into early learning , primary learning , secondary, tertiary higher red , vocational and life- long learning. rnEMPGI was formally established in June 2008 as a joint venture between EMPG (\\\"Education Media and Publishing Group\\\") and Istithmar World Capital. With an exclusive license to HMH\\\'s world class content and access to private equity capital, EMPGI benefits from a unique alliance between strategic and financial resources. This combination creates a platform to pursue investment opportunities with the flexibility and versatility that are critical to thriving in high growth markets.rnrn', 'Franchise India Barry \\\'Callaghan EMPGI Education Congress Change in education', '2:54', 'V', NULL, 'en', 2, 2, 6, 7592, 'A', '2011-05-20 02:59:30', NULL, NULL, 0, 0, 0, 0),
(62, 't2V43orehWg', NULL, 'Changing the face of education', 28, '', NULL, '', 0, 'When we talk about elementary education this is from kinder garden Class eight. But the scenario of secondary education is different. 97 Millions of students are in the age group of 14 to 18 and 1, 55,000 Secondary and senior secondary schools are there but only 40 million Students are study. Hence efficiency of secondary education is very low.', 'CBSE, Secondary Education, Efficiency', '3:58', 'V', NULL, 'en', 2, 2, 6, 2860, 'A', '2011-05-20 03:00:25', NULL, NULL, 0, 0, 0, 0),
(63, 'Zs2r6qUPSUM', NULL, 'Investing experience', 28, '', NULL, '', 0, 'Anything you do in education is contribution to the society.', 'Society, Education, Contribution', '2:47', 'V', NULL, 'en', 0, 0, 0, 2242, 'A', '2011-05-20 03:01:12', NULL, NULL, 0, 0, 0, 0),
(64, 'W5qxl0E-OEM', NULL, 'Managing with global expertise', 8, '', NULL, '', 41, 'A country which is increasingly globalizing, but culture of not getting Accountability in education system is a very backward phase. Quality of education can\\\\\\\'t exceed quality of teacher. Short term correction will not help role models, teacher success leadership.', 'Culture, Accountability, Teacher', '2:47', 'V', NULL, 'en', 0, 0, 0, 2511, 'A', '2011-05-20 03:02:07', NULL, NULL, 0, 0, 0, 0),
(65, '8fSEAqfwqmI', NULL, 'Focusing finance development', 8, '', NULL, '', 38, 'This education forum brings together educationist, investor to discuss about status and issues in current education system .Industry involve in design education curriculum and for industry to play a role in setting standard and to developed PPP model and IFC is working in both sides.', 'Education, IFC, Industry, Design', '3:25', 'V', NULL, 'en', 1, 1, 5, 3278, 'A', '2011-05-20 03:03:00', NULL, NULL, 0, 0, 0, 0);
