(805, '8mW66UCGVd0', NULL, 'Eretail a great place to be', 29, '', NULL, '', 0, 'eRetail Congress organised by Franchise India & Gitanjali', ' franchise, business, entrepreneur, congress, awards, 2012, www.franchiseindia.com, www.entreprenuerindia.com, Gaurav Marya, Sachin Marya,eRetail', '00.48', 'V', NULL, 'en', 0, 0, 0, 146, 'D', '2012-11-27 16:53:10', NULL, NULL, 0, 0, 0, 0),
(416, 'pkEwn_7JZEU', NULL, 'Bringing people and knowledge together', 3, '', NULL, '', 0, 'S. Chand is India\'s leading publishing company with unmatched market leadership over 7 decades. \"Bringing people and knowledge together\" is core to the mission of S. Chand Group and this has translated into \'Empowering Minds\'. S. Chand Books have touched three generations of Indian educated community. Today S. Chand needs no introduction. Its continuous commitment and endeavor of publishing quality books and meeting the needs right from primary level books to higher academic books in Engineering, Management, Commerce, Basic Sciences and others has built unmatched equity.\r\n', 'Franchise India  Amit Gupta   S. Chand Books   	Publishing  Books    Schools   Education Sector  ', '1.14', 'V', NULL, 'en', 0, 0, 0, 28, 'D', '2012-04-03 14:37:12', NULL, NULL, 0, 0, 0, 0),
