(897, '38Jbm6mHIlE', NULL, 'Gaurav Marya : Business Advisor, Entrepreneur & Author, Group Chairman of Franchise India ', 2, '', NULL, '', 15, 'The closest thing to a born entrepreneur, Gaurav Marya started his first enterprise at the age of 16. Over the years he has started and sold more than a dozen more. The businesses ranged from mobile phones, career advisory, and restaurants to the entertainment business. It was at the age of 24 that he found the focus that allowed him to retain his variety of interests in a successful manner. During a trip to the US in 1998, he saw how franchising had impacted the business scene there. He recognized that franchising was the fastest way of building entrepreneurship. In 1999 Gaurav set up Franchise India, which is today the largest integrated franchise and retail Solution Company in Asia.rnrnWithin the group identity of Franchise India Holdings Limited Gaurav has set up a number of initiatives and companies. Franchise India Exhibitions is a dedicated event management entity that extends franchise, retail and SME opportunities across tier 1, 2 and 3 cities in India and an annual show in the UAE. Franchise India Brands Limited is a leading business brokerage firm that facilitates the buying and selling of businesses. Francorp India is the Indian arm of the global leader of the franchising consulting industry Francorp. Franchise Guru provides solutions to Indian franchise investors. Franchise India Property provides information on the realty market, brokerage solutions to property owners and location solutions to franchise requirements.  Franchise Middle East enables entrepreneurs and investors to extend their footprint across the UAE, Bahrain, Qatar, Kuwait, Oman and Saudi Arabia. Bradford License India, the Indian arm of the New Jersey based Bradford Licensing, is the country\\\\\\\'s first complete licensing solution provider offering advisory, brokerage and management services. Indian Retailer has been established as a magazine and is now poised to become a leading consumption insight company. Entrepreneur India promotes and serves entrepreneurship in India; it conducts events, publishes Small Medium Entrepreneur, books and provides focused services to enable SMEs become big.', 'franchise,business,entrepreneur', '3.42', 'V', NULL, 'en', 321, 321, 847, 1876, 'D', '2012-12-22 18:11:35', NULL, NULL, 0, 0, 0, 0),
(898, '08-ndmjPWnA', NULL, 'Neeta Lulla at Franchise India, Small Business Congress 2010 ', 32, '', NULL, '', 0, 'Small Business Congress 2010 organised by Franchise India \r\n\r\nNeeta Lulla is an Indian fashion stylist and costume designer. She is the winner of four National Film Awards for Best Costume Design.', 'franchise, business, entrepreneur ', '3.36', 'V', NULL, 'en', 0, 0, 0, 388, 'D', '2012-12-22 18:13:28', NULL, NULL, 0, 0, 0, 0),
(899, 'QsFPw_bY-hg', NULL, 'SME sector to see an exponential growth in the next decade', 1, '', NULL, '', 10, 'Franchise India Holdings Limited is Asia\\\\\\\'s largest integrated franchise solution company since 1999. It is an absolute authority on franchising and licensing. FIHL has helped hundreds of investors in selecting the right franchise and have assisted numerous organisations in international and domestic franchise expansion. Knowledge, Opportunity, Network and Success are FIHL\\\\\\\'s key ingredients.', 'franchise, business', '6.24', 'V', NULL, 'en', 1, 1, 3, 3647, 'A', '2013-01-02 12:01:21', NULL, NULL, 0, 0, 0, 0),
