(1158, 'p1CgXck_-XQ', NULL, 'Anand Sharma, Union Minister Commerce and Industry and Textiles at \\\\\\\'India Food Services Report 2013\\\\\\\' ', 7, '', NULL, '', 34, 'The current size of the Indian food service industry is Rs 247,680 crore and is projected to grow to Rs 408,040 crore by 2018 at 11%, according to the India Food Services Report 2013, a comprehensive report on the Indian restaurant industry, released by the National Restaurant Association of India (NRAI) on April 23, 2013.rn rnReleased by Anand Sharma, Union Minister Commerce & Industry & Textiles the report gives detailed information on the industry size and highlights the industry\\\\\\\'s trends, growth and contributions to the economy.  rnrnThe Minister assured all help to the industry pertaining to tax regime, and coordination amongst various ministries for supporting food services. rnrnThrough the report, the NRAI revealed the opportunities and challenges, faced by the industry and suggested solutions to face them.rnrnKey findings of the reportrnIn terms of market segments, quick service restaurants (QSR) and casual dine-in formats account for 74% of the total chain market, while cafs make up for 12% with Fine Dining and Pub Bars Club & Lounges (PBCL) comprising the rest.rnrnThe chain and licensed standalone industry will contribute an estimated Rs 11,500-11,900 crore in 2013, projected to contribute more than double to Rs 24,600-25,000 crore by 2018.', 'business, entrepreneur,Union Minister,', '12.01', 'V', NULL, 'en', 4, 4, 8, 5913, 'A', '2013-04-24 16:01:01', NULL, NULL, 0, 0, 0, 0),
(1159, 'foMfv7fkYGA', NULL, 'Sunil Kapur of Pan India Food Solutions at  \\\\\\\'India Food Services Report 2013\\\\\\\' ', 7, '', NULL, '', 34, 'The current size of the Indian food service industry is Rs 247,680 crore and is projected to grow to Rs 408,040 crore by 2018 at 11%, according to the India Food Services Report 2013, a comprehensive report on the Indian restaurant industry, released by the National Restaurant Association of India (NRAI) on April 23, 2013.\\r\\n \\r\\nReleased by Anand Sharma, Union Minister Commerce & Industry & Textiles the report gives detailed information on the industry size and highlights the industry\\\\\\\'s trends, growth and contributions to the economy.  \\r\\n\\r\\nThe Minister assured all help to the industry pertaining to tax regime, and coordination amongst various ministries for supporting food services. \\r\\n\\r\\nThrough the report, the NRAI revealed the opportunities and challenges, faced by the industry and suggested solutions to face them.\\r\\n\\r\\nKey findings of the report\\r\\nIn terms of market segments, quick service restaurants (QSR) and casual dine-in formats account for 74% of the total chain market, while cafs make up for 12% with Fine Dining and Pub Bars Club & Lounges (PBCL) comprising the rest.\\r\\n\\r\\nThe chain and licensed standalone industry will contribute an estimated Rs 11,500-11,900 crore in 2013, projected to contribute more than double to Rs 24,600-25,000 crore by 2018.', 'Franchise, business, entrepreneur, retailer, education, awards, conference, food, restaurant, ', '03.45', 'V', NULL, 'en', 1, 1, 3, 6396, 'A', '2013-04-24 16:20:16', NULL, NULL, 0, 0, 0, 0),
(1160, 'Hbx5chiiFHQ', NULL, '\\\\\\\'India Food Services Report 2013\\\\\\\' Launch by NRAI', 7, '', NULL, '', 34, 'The current size of the Indian food service industry is Rs 247,680 crore and is projected to grow to Rs 408,040 crore by 2018 at 11%, according to the India Food Services Report 2013, a comprehensive report on the Indian restaurant industry, released by the National Restaurant Association of India (NRAI) on April 23, 2013. Released by Anand Sharma, Union Minister Commerce & Industry & Textiles the report gives detailed information on the industry size and highlights the industry\\\\\\\'s trends, growth and contributions to the economy. The Minister assured all help to the industry pertaining to tax regime, and coordination amongst various ministries for supporting food services. Through the report, the NRAI revealed the opportunities and challenges, faced by the industry and suggested solutions to face them. Key findings of the report In terms of market segments, quick service restaurants (QSR) and casual dine-in formats account for 74% of the total chain market, while cafs make up for 12% with Fine Dining and Pub Bars Club & Lounges (PBCL) comprising the rest. The chain and licensed standalone industry will contribute an estimated Rs 11,500-11,900 crore in 2013, projected to contribute more than double to Rs 24,600-25,000 crore by 2018.', 'food, restaurant', '00.17', 'V', NULL, 'en', 0, 0, 0, 6203, 'A', '2013-04-24 16:32:26', NULL, NULL, 0, 0, 0, 0),
(1161, 'jjehE-aS__Y', NULL, 'Audio - Video Max Expo 2013, New Delhi ', 1, '', NULL, '', 0, 'The 10th Edition of India\\\'s Premier Audio Video Home Entertainment Expo AV Max Expo 2013 was held at Hotel Crowne Plaza, in New Delhi recently. With over 100 brands the stage was set for a mesmerising AV experience.The expo was started in the year 2002 by AV Max which is a special interest Audiophile magazine by Network 18. Showcasing a range of products from media players to high end loud speakers. From flat panels to 5.1 and even 7.2 home entertainment systems, the expo had it all. With participants names including brands such as Dali, Arrow, FXE, Triangle, Tangent, Cinbels, Epson, Lakozy, Paradigm, Tanoy, Lab Groupen, Olive, Kingdom Royal etc and various distributors.No audio video experience is ever complete without actually seeing the products in action and so 22 demo rooms were arranged, were visitors could see and hear these amazing products in all their glory.Adding comfort to the overall audio video experience was the comfortable and luxurious recliners. The expo received and overwhelming response with visitors from all across the country.', 'audio, music, AV max, ', '06.07', 'V', NULL, 'en', 0, 0, 0, 604, 'D', '2013-04-26 17:03:24', NULL, NULL, 0, 0, 0, 0),
(1162, '5Ufnyn1KBwU', NULL, 'Garment Technology Expo 2013', 1, '', NULL, '', 0, 'Garment Technology Expo 2013, NSIC Exhibition Complex , New Delhi\\r\\n', 'franchise, business, expo, garment, technology, ', '01.58', 'V', NULL, 'en', 0, 0, 0, 2106, 'A', '2013-04-30 12:47:17', NULL, NULL, 0, 0, 0, 0),
(1163, 'YLIGG7-3Z7Q', NULL, 'Audio - Video Max Expo 2013 by Network 18', 1, '', NULL, '', 0, 'The 10th Edition of India\\\\\\\'s Premier Audio-Video Home Entertainment Expo AV Max Expo 2013 was held at Hotel Crowne Plaza, in New Delhi recently. With over 100 brands the stage was set for a mesmerising AV experience. The expo was started in the year 2002 by AV Max which is a special interest Audiophile magazine by Network 18. Showcasing a range of products from media players to high end loud speakers. From flat panels to 5.1 and even 7.2 home entertainment systems, the expo had it all. With participants names including brands such as Dali, Arrow, FXE, Triangle, Tangent, Cinbels, Epson, Lakozy, Paradigm, Tanoy, Lab Groupen, Olive, Kingdom Royal etc and various distributors. No audio video experience is ever complete without actually seeing the products in action and so 22 demo rooms were arranged, were visitors could see and hear these amazing products in all their glory.Adding comfort to the overall audio video experience was the comfortable and luxurious recliners. The expo received and overwhelming response with visitors from all across the country.', 'Sandeep Khosla, audio, video, expo, 2013, max, network 18', '06.13', 'V', NULL, 'en', 0, 0, 0, 6492, 'A', '2013-05-01 13:08:33', NULL, NULL, 0, 0, 0, 0),
