(3364, 'SlsSBqBz1rM', NULL, 'Hindi EV news Bulletin|हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>हिंदी ईवी समाचार बुलेटिन</strong><strong>|</strong> इलेक्ट्रिक थ्री-व्हीलर मोबिलिटी को बढ़ावा देने के लिए रेवफिन ने बजाज ऑटो से किया करार।इस साझेदारी का लक्ष्य बजाज की इलेक्ट्रिक हाई-स्पीड थ्री-व्हीलर पेशकश में तेजी लाना है।</p>', '', '5:09', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-08-20 07:21:31', '2024-08-20 07:21:31', '2024-08-20 07:23:03', 0, 0, 0, 0),
(3365, 'Gz5yRryl9-w', NULL, 'Panel: Start-ups  Changing EV Landscape in India', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">Entrepreneur India Organized India&rsquo;s Largest Electric Vehicle Show. India EV Expo &amp; Conference 2024 on 29-30 June in Tamil Nadu. The panel discussed, How the govt is supporting start-ups ecosystem to make them big.</p>', '', '52:17', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-08-21 05:52:21', '2024-08-21 05:52:21', '2024-08-21 05:52:21', 0, 0, 0, 0),
