(3371, 'JgyR4UpxFN4', NULL, 'Hindi EV news Bulletin|हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>हिंदी ईवी समाचार बुलेटिन|</strong> उत्तर प्रदेश सरकार ने घोषणा की है कि मजबूत हाइब्रिड और प्लग-इन हाइब्रिड वाहनों के लिए शून्य पंजीकरण कर नीति में कोई बदलाव या वापसी नहीं होगी। सरकार इस हाइब्रिड नीति को अक्टूबर 2025 तक जारी रखेगी।&nbsp; &nbsp;</p>', '', '5:10', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-08-22 06:46:50', '2024-08-22 06:46:50', '2024-08-22 06:47:45', 0, 0, 0, 0),
(3372, '6ec3tNrLgAk', NULL, 'Panel: Delivering A Seamless Charging Experience With Charging Standardisation', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">Entrepreneur India Organized India&rsquo;s Largest Electric Vehicle Show. India EV Expo &amp; Conference 2024 on 29-30 June in Tamil Nadu, The panel discussed EV quick charging parks that adapts to changing requirements.</p>', '', '55:44', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-08-23 03:43:30', '2024-08-23 03:43:30', '2024-08-23 03:43:30', 0, 0, 0, 0),
(3373, '0TMldC3_uFw', NULL, 'Keynote : Embracing EVs in energy transition of India: Opportunities and Challenges', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">Entrepreneur India Organized India&rsquo;s Largest Electric Vehicle Show, India EV Show 2024, on last days of June Mr. Harish Mehta, CEO, Reliance-bp Mobility Limited said it would be a great deal working together with tamil nadu Govt. for the future of the EV sector in india.</p>', '', '21:45', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-08-23 03:45:34', '2024-08-23 03:45:34', '2024-08-23 03:45:34', 0, 0, 0, 0),
(3374, 'THAL94LyPsg', NULL, 'Hindi EV news Bulletin|हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>हिंदी ईवी समाचार बुलेटिन|</strong>ऑल-इलेक्ट्रिक इंटरसिटी बस स्टार्टअप फ्रेश बस (Fresh Bus)&nbsp; ने 87.5 करोड़ रुपये (10.5 मिलियन अमेरिकी डॉलर) की फंडिंग जुटाई है। इस फंडिंग राउंड का नेतृत्व एक शुरुआती चरण के परिवहन-केंद्रित निवेश वीसी फंड मनिव ( Maniv) ने किया।</p>', '', '4:35', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-08-23 06:28:51', '2024-08-23 06:28:51', '2024-08-23 06:29:41', 0, 0, 0, 0),
(3375, 'SXDQto-CMLw', NULL, 'Hindi EV news Bulletin|हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>हिंदी ईवी समाचार बुलेटिन|</strong>इलेक्ट्रिक दोपहिया वाहन मैन्युफैक्चरर ओला इलेक्ट्रिक को अपने दो और वाहनों के लिए पीएलआई लाभ के लिए प्रमाणन प्राप्त हुआ है। ओला के S1X स्कूटर के तीन और चार किलोवाट (KWH) वाले मॉडल्स को सरकार की पीएलआई योजना के तहत योग्य माना गया है।</p>', '', '4:59', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-08-28 07:37:47', '2024-08-28 07:37:47', '2024-08-28 07:37:47', 0, 0, 0, 0),
(3376, 'r-WRqXfUuxI', NULL, 'मेटल की कीमतों का ईवी उद्योग पर प्रभाव', 11, '', NULL, '', 0, '<p style=\"text-align: justify;\">बेटएक्स एनर्जी के सह-संस्थापक और सीईओ उत्कर्ष सिंह ने कहा &ldquo;हमारे उद्योग की सबसे बड़ी चुनौती यह है कि मेटल की कीमतें लगातार ऊपर-नीचे होती रहती हैं। और पिछले 1.5 वर्षों से ये गिर रही हैं। इसलिए, यह एक बड़ी चुनौती है। निवेशक और सभी लोग सवाल करते हैं कि आपकी बिक्री कम हो रही है या आपकी बिक्री उतनी नहीं बढ़ रही है जितना आप बता रहे हैं,जब की बिक्री मेटल की कीमतों से जुड़ी होती है।\"</p>', '', '12:00', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-08-29 09:41:22', '2024-08-29 09:41:22', '2024-08-29 09:41:22', 0, 0, 0, 0),
(3377, 'sogE1v0dv54', NULL, 'Hindi EV news Bulletin|हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>हिंदी ईवी समाचार बुलेटिन|</strong> बजाज ऑटो पहली ऐसी ऑटो कंपनी बन गई है, जिसे भारत में बनाए गए सभी 15 इलेक्ट्रिक वाहन मॉडलों के लिए डोमेस्टिक वैल्यू एडिशन (DVA) सर्टिफिकेट मिला है। भारी उद्योग मंत्रालय (MHI) ने छह कंपनियों द्वारा प्रस्तुत किए गए 74 मॉडलों में से 50 मॉडलों को मंजूरी दी है।</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>', '', '4:21', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-09-02 12:18:19', '2024-09-02 12:18:19', '2024-09-02 12:18:19', 0, 0, 0, 0),
(3378, 'HoDrZGkCy4w', NULL, 'Hindi EV News Bulletin | हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p><strong>हिंदी ईवी समाचार बुलेटिन </strong><strong>|</strong> एलियांज पार्टनर्स इंडिया और पल्स एनर्जी ने देशभर में अपने ग्राहकों के लिए ईवी &nbsp;ओनरशिप अनुभव को बेहतर बनाने के लिए एक रणनीतिक साझेदारी की घोषणा की है।</p>\r\n<p>&nbsp;</p>', '', '4:47', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-09-11 09:37:07', '2024-09-11 09:37:07', '2024-09-11 09:37:07', 0, 0, 0, 0),
(3379, 'hnT44B1hHRo', NULL, 'ई-मोबिलिटी: नई तकनीकों के लिए निवेश और हिस्सेदारों की भूमिका', 11, '', NULL, '', 0, '<p style=\"text-align: justify;\">डब्ल्यूआरआई इंडिया की ग्लोबल इलेक्ट्रिक मोबिलिटी में डायरेक्टर क्रिस्टीना अल्बुकर्क ने कहा ई-मोबिलिटी नई तकनीकों को लाकर इनोवेशन को बढ़ावा दे रही है। यह ऊंची लागत को कम करने के लिए नए व्यापार मॉडल पेश कर रही है और उपयोगिता कंपनियों, निवेशकों और वाहन निर्माताओं जैसे लोगों को शामिल कर रही है। इससे परिवहन को पर्यावरण के अनुकूल बनाने और विभिन्न प्रकार के ट्रांसपोर्ट में सुधार लाने में मदद मिल रही है।</p>', '', '2:24', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-09-18 12:14:37', '2024-09-18 12:14:37', '2024-09-18 12:14:37', 0, 0, 0, 0),
(3380, 'Ocd9ZI0Bghk', NULL, 'आईआईटी मद्रास की इलेक्ट्रिक मोबिलिटी में सफलता की कहानी', 11, '', NULL, '', 0, '<h3>आईआईटी मद्रास&nbsp; के प्रोफेसर डॉ. गीता कृष्णन रामादुरई ने ईवी शिक्षा पर अपने विचार साझा करते हुए बताया कि आईआईटी मद्रास ने \"मास्टर्स इन इलेक्ट्रिक मोबिलिटी\" नामक एक नया कार्यक्रम शुरू किया है। यह एक अनूठा कार्यक्रम है, जो मुख्य रूप से उद्योग के पेशेवरों के लिए डिज़ाइन किया गया है, हालांकि छात्र भी इसमें भाग ले सकते हैं। हम ईवी उद्योग से संबंधित व्यक्तियों को इसमें शामिल होने के लिए आमंत्रित करते हैं। इस कार्यक्रम ने देश में इलेक्ट्रिक मोबिलिटी शिक्षा में क्रांति ला दी है।</h3>\r\n<p>&nbsp;</p>', '', '1:59', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-09-18 12:33:26', '2024-09-18 12:33:26', '2024-09-19 04:11:45', 0, 0, 0, 0),
(3381, 'IJtM1BlYQr0', NULL, 'ई-बस तैनाती  में वित्तीय और चार्जिंग इन्फ्रा की समस्या', 11, '', NULL, '', 0, '<p style=\"text-align: justify;\">भारत के ई-बस प्रोग्राम को बढ़ाने के लिए बहुत अधिक पैसे की ज़रूरत होती है, इसलिए सही तरीके से फंडिंग करना बहुत ज़रूरी है। डब्ल्यूआरआई इंडिया में इंटीग्रेटेड ट्रांसपोर्ट के प्रोग्राम हेड अविनाश दुबेदी ने&nbsp;कहा की डब्ल्यूआरआई इंडिया की &ldquo;भारत में बड़े पैमाने पर इलेक्ट्रिक बस प्रोग्राम लागू करने के लिए वित्तीय चुनौतियों का आकलन&rdquo; यह रिपोर्ट (वर्किंग पेपर) इस बात को समझने की कोशिश करती है कि ई-बसों की फंडिंग में शुरुआत में क्या-क्या चुनौतियाँ आती हैं, खासकर बैंकों और बस ऑपरेटर्स के नजरिए से। इसके लिए कई जानकारों और स्टेकहोल्डर्स से बातचीत की गई है।</p>', '', '6:09', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-09-18 12:44:45', '2024-09-18 12:44:45', '2024-09-18 12:44:45', 0, 0, 0, 0),
(3382, '5sUr1zrfobg', NULL, 'इलेक्ट्रिक बसों के विकास में GIZ और सूरत का सहयोग', 11, '', NULL, '', 0, '<p style=\"text-align: justify;\">GIZ India के लीड-इलेक्ट्रिक मोबिलिटीअमेघ गोपीनाथ ने कहा हम इलेक्ट्रिक बसों के क्षेत्र में भारी उद्योग मंत्रालय और सूरत शहर के साथ काम कर रहे हैं। हाल ही में शुरू की गई इलेक्ट्रिक बस योजना और 2030 तक 50,000 इलेक्ट्रिक बसों के लक्ष्य के तहत, हम अनुबंधों, योजना, शेड्यूलिंग और तैनाती पर ध्यान केंद्रित कर रहे हैं। हम सूरत के लिए एक योजना तैयार कर रहे हैं और CSL, ASRTU, MOHUA और MHI के साथ नीति और योजना स्तर पर काम कर रहे हैं।</p>', '', '3:16', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-09-19 04:03:06', '2024-09-19 04:03:06', '2024-09-19 04:03:06', 0, 0, 0, 0),
(3383, 'hnT44B1hHRo', NULL, 'E-Mobility: Innovating Cost-Effective Solutions and Stakeholder Roles', 11, '', NULL, '', 0, '<p style=\"text-align: justify;\">Ms. Cristina Albuquerque, Director, Global Electric Mobility, WRI India said E-mobility is driving innovation by introducing new business models to address higher capital costs and engage stakeholders like utility companies, investors, and OEMs. It supports decarbonising transport and implementing solutions across various transport modes.</p>', '', '2:24', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-09-19 04:45:56', '2024-09-19 04:45:56', '2024-09-19 05:07:48', 0, 0, 0, 0),
(3384, 'Ocd9ZI0Bghk', NULL, 'Ather Two-Wheeler: IIT Madras\' Success Story in Electric Mobility', 15, '', NULL, '', 0, '<p>Dr. Gitakrishnan Ramadurai from IIT Madras shared insights on EV education, stating that IIT Madras has launched a new program called\"Masters in Electric Mobility.\" This is a unique program primarily designed for industry professionals, though students can also participate. We invite individuals from the EV industry to join us. This program has revolutionized electric mobility education in the country.</p>', '', '1:59', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-09-19 05:13:00', '2024-09-19 05:13:00', '2024-09-19 05:15:16', 0, 0, 0, 0),
(3385, 'IJtM1BlYQr0', NULL, 'Challenges and Solutions in E-Bus Deployment', 11, '', NULL, '', 0, '<p style=\"text-align: justify;\">WRI India\'s report &ldquo;Assessing financing challenges for implementing the large -scale electric bus program in india&rdquo; highlights the initial funding challenges, especially from the perspectives of banks and operators. Mr. Avinash Dubedi, Program Head of Integrated Transport at WRI India said The working paper presents insights from OEMs, operators, and lenders, highlighting key challenges in e-bus deployment and offering solutions to mitigate associated risks.</p>', '', '6:09', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-09-19 05:18:16', '2024-09-19 05:18:16', '2024-09-19 05:21:46', 0, 0, 0, 0),
(3386, '5sUr1zrfobg', NULL, 'Changes in Electric Buses: From Urban to Inter-State Travel', 15, '', NULL, '', 0, '<p style=\"text-align: justify;\">In talks with Mr.Amegh Gopinath, Lead-Electric Mobility, GIZ India said, We are working with the Ministry of Heavy Industries and the city of Surat in the field of electric buses. Under the recently launched electric bus scheme and the target of 50,000 electric buses by 2030, we are focusing on contracts, planning, scheduling, and deployment. We are preparing a plan for Surat and are working at the planning and policy level with CSL, ASRTU, MOHUA, and MHI.</p>', '', '3:16', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-09-19 05:25:05', '2024-09-19 05:25:05', '2024-09-19 05:25:05', 0, 0, 0, 0),
(3387, 'MRLmjmKryvM', NULL, 'New Dashboard Tracks EV Sales, Charging Infrastructure, and Adoption Metrics', 15, '', NULL, '', 0, '<p style=\"text-align: justify;\">Ms. Aishwarya Raman, Executive Director, OMI Foundation Said OMI Foundation\'s \"EV-Ready India\" dashboard, launched in October 2023, compiles electric vehicle data, including sales, charging infrastructure, state-wise adoption, emissions reduction, and total cost of ownership. It helps track EV policies, manufacturers, and regional advantages to accelerate electric mobility adoption.</p>', '', '2:28', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-09-19 05:54:59', '2024-09-19 05:54:59', '2024-09-19 05:54:59', 0, 0, 0, 0),
(3388, 'MRLmjmKryvM', NULL, 'इलेक्ट्रिक मोबिलिटी: सटीक डेटा से नीति निर्माण को मिलेगी नई दिशा', 11, '', NULL, '', 0, '<p style=\"text-align: justify;\">ओएमआई फाउंडेशन ट्रस्ट की एग्जीक्यूटिव डायरेक्टर ऐश्वर्या रमन ने कहा EV-Ready India नाम से एक नया लॉन्च किया है, जो भारत में इलेक्ट्रिक मोबिलिटी ट्रांज़िशन से जुड़ी सभी प्रकार की जानकारी को एक ही जगह पर संकलित करता है।इस डैशबोर्ड में आपको इलेक्ट्रिक वाहन बिक्री, चार्जिंग इंफ्रास्ट्रक्चर, और राज्य एवं जिला स्तर पर ईवी अपनाने का डाटा मिलेगा। आप यह भी देख सकते हैं कि आपके निर्माता कौन हैं और कितना प्रदूषण बचाया जा रहा है।</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>', '', '2:28', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-09-19 05:57:35', '2024-09-19 05:57:35', '2024-09-19 05:57:35', 0, 0, 0, 0),
(3389, '1LZOcLjN0tg', NULL, 'Hindi EV News Bulletin| हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">ग्रिव्स इलेक्ट्रिक मोबिलिटी ने बताया कि भारी उद्योग मंत्रालय (MHI) ने चार इलेक्ट्रिक 2W - Nexus, Primus, Magnus, और Zeal को एक सरकारी योजना (EMPS) के तहत पंजीकरण की मंजूरी दी है। इस मंजूरी के साथ कंपनी को इलेक्ट्रिक वाहनों के लिए सरकार की तरफ से मिलने वाली सब्सिडी का फायदा मिलेगा।</p>', '', '5:03', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-09-20 09:04:58', '2024-09-20 09:04:58', '2024-09-20 09:04:58', 0, 0, 0, 0),
(3390, 'q0mtvQuhUio', NULL, 'Hindi EV News Bulletin| हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">भारत की प्रमुख इलेक्ट्रिक वाहन निर्माता कंपनी टाटा मोटर्स मुफ्त चार्जिंग और भारी छूट देकर उपभोक्ताओं को आकर्षित कर रही है, जबकि प्रतिस्पर्धी एमजी मोटर ने अपनी पहली बैटरी रेंटल योजना शुरू की है, जो स्वच्छ कारों की बिक्री बढ़ाने के उद्देश्य से बनाई गई रणनीतियों का हिस्सा है।</p>', '', '4:39', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-09-28 11:45:31', '2024-09-28 11:45:31', '2024-09-28 11:45:31', 0, 0, 0, 0),
(3391, 'rOQW6xCCqOk', NULL, 'Hindi EV News Bulletin| हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>हिंदी ईवी समाचार बुलेटिन|</strong> डिजिटल ऑटोमोटिव आफ्टरमार्केट प्लेटफॉर्म, myTVS, ने पूरे भारत में लास्ट माइल ईवी फ्लीट ऑपरेटरों के लिए अपने \'मोबिलिटी-एज-अ-सर्विस\' (MaaS) प्लेटफॉर्म की शुरुआत की। यह प्लेटफ़ॉर्म OEMs को कई तरह की सेवाएँ प्रदान करने की सुविधा देता है।</p>', '', '5:06', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-10-01 05:39:45', '2024-10-01 05:39:45', '2024-10-01 05:43:32', 0, 0, 0, 0);
INSERT INTO `fihl_podcstvideo` (`sno`, `videoID`, `podcast_id`, `title`, `category`, `image`, `image_path`, `maxresimage`, `subcategory`, `description`, `keyword`, `duration`, `podcast_type`, `podcast_link`, `pod_lang`, `total_comment`, `total_votes`, `total_value`, `views`, `status`, `create_date`, `created_at`, `updated_at`, `fbshare`, `twittershare`, `linkedinshare`, `whasupshare`) VALUES
(3392, 'QqF6bw5VYL8', NULL, 'EV News Bulletin| हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>हिंदी ईवी समाचार बुलेटिन| </strong>उत्तर प्रदेश में इलेक्ट्रिक वाहनों को बढ़ावा देने के लिए सरकार ने एक्सप्रेसवे और हाईवे पर ई-चार्जिंग स्टेशनों के निर्माण की बड़ी योजना बनाई है, जिससे सड़क पर उतरने वाले ई-वाहनों की चार्जिंग सुविधा को बेहतर किया जा सके। इसको लेकर योगी सरकार की ओर से दिशा-निर्देश जारी किए गए हैं।&nbsp;</p>', '', '5:12', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-10-07 09:01:09', '2024-10-07 09:01:09', '2024-10-07 09:01:09', 0, 0, 0, 0),
(3393, 'XWP0ChBPc-8', NULL, 'EV News Bulletin| हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">उर्जा मोबिलिटी एक स्टार्टअप कंपनी है जो इलेक्ट्रिक वाहनों (EV) के लिए बैटरी लीजिंग का काम करती है। इसका मतलब है कि यह कंपनी बैटरी को खरीदने की जगह उन्हें किराए पर देती है, जिससे EV खरीदना सस्ता हो जाता है। हाल ही में, उर्जा मोबिलिटी ने अपने नए फंडिंग राउंड में 100 करोड़ रुपये (लगभग 12 मिलियन डॉलर) जुटाए हैं।</p>', '', '5:12', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-10-23 10:55:03', '2024-10-23 10:55:03', '2024-10-23 10:55:03', 0, 0, 0, 0),
(3394, '98bJYgdiJk8', NULL, 'जर्मनी ने निवेश और सहयोग के साथ भारत में ई-मोबिलिटी को दिया बढ़ावा', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>भारत और भूटान में जर्मन राजदूत डॉ.फिलिप एकरमैन</strong> ने कहा जर्मनी भारत में इलेक्ट्रिक मोबिलिटी को बढ़ावा देने के लिए कई गतिविधियों के माध्यम से सक्रिय रूप से काम कर रहा है। इसका एक प्रमुख उदाहरण मर्सिडीज है, जो एक जर्मन कार कंपनी है और पुणे में पहले से ही इलेक्ट्रिक वाहनों का उत्पादन कर रही है। इसके साथ ही उन्होंने बताया ई-मोबिलिटी को सपोर्ट देने के लिए चार्जिंग इंफ्रास्ट्रक्चर की स्थापना में निवेश किया गया है, जिसमें दिल्ली के निजामुद्दीन के पास एक अत्याधुनिक चार्जिंग सुविधा शामिल है।</p>', '', '1:26', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-10-24 09:05:53', '2024-10-24 09:05:53', '2024-10-24 09:08:32', 0, 0, 0, 0),
(3395, '98bJYgdiJk8', NULL, 'Boosting E-Mobility: German-Indian Automotive Collaboration', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>Dr. Phillip Ackermann,German Ambassador to India and Bhutan</strong> Said that Germany is actively promoting electric mobility in India through various initiatives. Mercedes is already producing electric vehicles in Pune, and investments have been made in charging facilities, including one near Nizamuddin in Delhi. There is growing cooperation between German and Indian suppliers, especially in battery production, to drive e-mobility growth on Indian roads. The private sector is playing a key role in this effort.</p>', '', '1:26', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-10-24 09:08:04', '2024-10-24 09:08:04', '2024-10-24 09:08:20', 0, 0, 0, 0),
(3396, 'mrROXrowI-Q', NULL, 'ग्रीन हाइड्रोजन एक क्षेत्र नही बल्की एक अर्थव्यवस्था है -  अर्पित शर्मा', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">स्किल काउंसिल फॉर ग्रीन जॉब के CEO अर्पित शर्मा ने कहा,\"हमने वेस्ट मैनेजमेंट क्षेत्र में लगभग 4,50,000 स्वच्छता कर्मियों और डीस्लजिंग ऑपरेटरों को प्रशिक्षित किया है। अब, हम ग्रीन हाइड्रोजन पर ध्यान केंद्रित कर रहे हैं, जो भारत के सबसे बड़े उभरते क्षेत्रों में से एक है, और हमने इस क्षेत्र में क्षमता निर्माण की शुरुआत की है।</p>', '', '2:19', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-10-25 10:58:15', '2024-10-25 10:58:15', '2024-10-25 10:58:15', 0, 0, 0, 0),
(3397, 'mrROXrowI-Q', NULL, 'Empowering India\'s Green Workforce: The Role of SCGJ', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">The CEO of the Skill Council for Green Jobs, Arpit Sharma, said, \"We have trained nearly 450,000 sanitation workers and de-sludging operators in the waste management sector. Now, we are focusing on green hydrogen, which is one of the largest emerging sectors in India, and we have initiated capacity building in this area.</p>', '', '2:19', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-10-25 11:00:27', '2024-10-25 11:00:27', '2024-10-25 11:00:27', 0, 0, 0, 0),
(3398, 'ZrFqawYnvjQ', NULL, 'हरित ऊर्जा: ईवी चार्जिंग के लिए नीतियों में बदलाव का समय', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>एनएसईएफआई</strong><strong>&nbsp;&nbsp;</strong><strong>के सीईओ सुब्रमण्यम पुलिपाका</strong>&nbsp;ने इस विषय पर बताया की ईवी चार्जिंग इन्फ्रास्ट्रक्चर मुख्य रूप से ग्रिड-आधारित चार्जिंग पर निर्भर है। जैसे-जैसे हम अपनी बिजली मिश्रण में सौर और पवन ऊर्जा का हिस्सा बढ़ाते हैं, हम ई-मोबिलिटी की पूरी मूल्य श्रृंखला को हरा-भरा बनाने की स्थिति में होंगे। एक संघ के रूप में, हम इस पर सक्रिय रूप से काम कर रहे हैं।</p>', '', '4:41', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-11-05 06:57:18', '2024-11-05 06:57:18', '2024-11-05 06:57:18', 0, 0, 0, 0),
(3399, 'ZrFqawYnvjQ', NULL, 'Green Energy Revolution: Policies and Innovations in EV Charging', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">NSEFI, CEO, Subramanyam Pulipaka stated that a solar-powered EV charging station has been established in Hauz Khas village. This will help us understand how to increase the use of green energy for charging and how this model can be adopted in other states as well.</p>', '', '4:41', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-11-05 06:59:11', '2024-11-05 06:59:11', '2024-11-05 06:59:11', 0, 0, 0, 0),
(3400, 'vEyIN7XnjuM', NULL, 'Green Hydrogen: A Key Driver for Sustainable Electric Vehicle Innovation', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">A.K. Rastogi, Chairman, Task Force, Sustainable Just Transition &amp; Green hydrogen, Govt. of Jharkhand, stated that the Jharkhand government is taking active steps to support and collaborate in the field of green hydrogen. We are introducing a policy to promote green hydrogen to attract investments, as it represents a new revenue sector.</p>', '', '3:55', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-11-05 07:01:20', '2024-11-05 07:01:20', '2024-11-05 07:01:20', 0, 0, 0, 0),
(3401, 'vEyIN7XnjuM', NULL, 'सस्टेनेबिलिटी की दिशा में झारखंड सरकार का प्रमुख कदम', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong> झारखंड सरकार में सस्टेनेबल जस्ट ट्रांजिशन एंड ग्रीन हाइड्रोजन,टास्क फोर्स के चेयरमैन एके रस्तोगी</strong> ने कहा झारखंड सरकार ग्रीन हाइड्रोजन के क्षेत्र में सहयोग और सपोर्ट के लिए सक्रिय कदम उठा रही है। सरकार ग्रीन हाइड्रोजन को प्रोत्साहित करने के लिए एक नीति ला रही हैं ताकि निवेश को आकर्षित किया जा सके, क्योंकि यह एक नया राजस्व क्षेत्र है।</p>', '', '3:55', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-11-05 07:04:38', '2024-11-05 07:04:38', '2024-11-05 07:04:38', 0, 0, 0, 0),
(3402, 'GV5sGA7yCjw', NULL, 'How TANSTIA is Revolutionizing Tamil Nadu\'s MSME Landscape', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">Tamil Nadu Small and Tiny Industries Association (<strong>TANSTIA</strong>),President <strong>C.K. Mohan</strong> highlighted the importance of adapting to new technologies and changes for every entrepreneur. It depends on their ability to learn new things and invest in them. While older entrepreneurs may not see these changes as necessary, the newer, more educated generation finds it easier to understand. Three things are essential for this: awareness, proper training, and the capacity to invest. Additionally, there should be demand in the market. Together, these factors help an entrepreneur make the right decisions.</p>', '', '6:03', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-11-05 07:06:48', '2024-11-05 07:06:48', '2024-11-05 07:06:48', 0, 0, 0, 0),
(3403, 'GV5sGA7yCjw', NULL, 'कैसे TANSTIA बदल रहा है तमिलनाडु में एमएसएमई की तस्वीर', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>तमिलनाडु स्मॉल एंड टिनी इंडस्ट्रीज एसोसिएशन (</strong><strong>TANSTIA)&nbsp;</strong><strong>के प्रेसिडेंट सीके मोहन</strong>&nbsp;ने एमएसएमई के विकास और सस्टेनेबिलिटी के बारे में बताते हुए कहा &nbsp;हर उद्यमी को नई टेक्नोलॉजी और बदलावों के साथ तालमेल बिठाना होता है। यह इस पर निर्भर करता है कि वह नई चीजें सीखने और उसमें पैसा लगाने में सक्षम है या नहीं। पुराने जमाने के उद्यमियों को ये चीजें उतनी जरूरी नहीं लग सकतीं, लेकिन नई पीढ़ी, जो अधिक शिक्षित है, उसे यह समझना आसान हो सकता है। इसके लिए तीन चीजें जरूरी हैं: जागरूकता, सही प्रशिक्षण, और निवेश की क्षमता। इसके साथ ही बाजार में मांग भी होनी चाहिए। ये सभी चीजें मिलकर एक उद्यमी को सही निर्णय लेने में मदद करती हैं।</p>', '', '6:03', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-11-05 07:09:11', '2024-11-05 07:09:11', '2024-11-05 07:09:11', 0, 0, 0, 0),
(3404, 'JusgWm-CcZ4', NULL, 'EV News Bulletin| हिंदी ईवी समाचार बुलेटिन', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>हिंदी ईवी समाचार बुलेटिन।</strong> बीएसई-लिस्टेड नॉन-बैंकिंग फाइनेंशियल कंपनी (एनबीएफसी) मेगा कॉर्पोरेशन ने एक नई शाखा \"लेंडिंगो\" की घोषणा की है, जो इलेक्ट्रिक वाहनों, जिसमें ईवी बैटरियां, रिक्शा और संबंधित व्यवसायों के लिए वित्तपोषण प्रदान करेगी। लेंडिंगो का उद्देश्य बढ़ते हुए ईवी क्षेत्र का समर्थन करना और सतत समाधान में योगदान देना है।</p>', '', '5:35', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-11-06 10:47:12', '2024-11-06 10:47:12', '2024-11-06 10:47:12', 0, 0, 0, 0),
(3405, 'wxeLcOvd7T4', NULL, 'SIDBI ‘Srijan’ & ‘GIFT’: Fueling MSME Innovation', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">SIDBI Chief General Manager, R.K. Singh, stated that SIDBI is a leading financial institution for MSMEs, covering the entire value chain from micro, small, and medium enterprises. In terms of innovation, we run several programs, one of which is \"Srijan,\" where any MSME or start-up interested in adopting the latest technology can receive support under this program.</p>', '', '2:48', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-11-07 10:12:14', '2024-11-07 10:12:14', '2024-11-07 10:12:14', 0, 0, 0, 0),
(3406, 'wxeLcOvd7T4', NULL, 'सिडबी के \' Srijan\' और \'GIFT\' से एमएसएमई में इनोवेशन को बढ़ावा', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>सिडबी के चीफ जनरल मैनेजर आरके सिंह</strong>&nbsp;ने कहा एमएसएमई के लिए सिडबी एक प्रमुख वित्तीय संस्था है जो माइक्रो, स्मॉल और मीडियम एंटरप्राइजेज के लिए काम करती है, शुरुआत से लेकर माइक्रो, स्मॉल और मीडियम एंटरप्राइजेज तक के पूरे वैल्यू चेन पर। इनोवेशन के संबंध में हम कुछ कार्यक्रम चलाते हैं, जिनमें से एक है \"सृजन\" (SRIJAN), जहां कोई भी एमएसएमई या स्टार्टअप अगर नवीनतम तकनीक में जाना चाहता है, तो हम इस कार्यक्रम के तहत उन्हें सहायता प्रदान कर सकते हैं।</p>', '', '2:48', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-11-07 11:34:59', '2024-11-07 11:34:59', '2024-11-07 11:34:59', 0, 0, 0, 0),
(3407, '5vD1xCroPhs', NULL, 'Give New Life to Old Vehicles Convert Petrol Cars to Electric !', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">Sivasankari TP, Founder and Managing Director of AR4 Tech, said that we primarily convert existing IC vehicles into electric vehicles. Indian people often have an emotional attachment to their old vehicles, and they want to preserve them. Therefore, instead of sending these vehicles to scrap, we are giving them a new life. We convert these old petrol-diesel vehicles into electric vehicles so they can be used again, and their value is maintained.</p>', '', '5:00', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-11-18 04:00:48', '2024-11-18 04:00:48', '2024-11-18 04:00:48', 0, 0, 0, 0),
(3408, '5vD1xCroPhs', NULL, 'सिवासंकरी टीपी की पहल मौजूदा आईसी वाहनों को इलेक्ट्रिक में बदलना', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\">आईसी वाहनों को इलेक्ट्रिक में बदलने के लिए नए वाहनों के निर्माण से कम लागत आती है। इसके अलावा, पुराने वाहनों का पुनः उपयोग करने से नए वाहनों की तुलना में पर्यावरणीय प्रभाव भी कम होता है। इससे व्यापार में टिकाऊ और लागत प्रभावी समाधान मिलता है।</p>', '', '5:00', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-11-18 04:08:00', '2024-11-18 04:08:00', '2024-11-18 04:08:00', 0, 0, 0, 0),
(3409, 'TlepiYMeeaE', NULL, 'EV News Bulletin', 2, '', NULL, '', 0, '<p style=\"text-align: justify;\"><strong>EV News Bulletin|</strong>Suzuki Motor Corp has unveiled its first electric car, the \"e-Vitara.\" The company plans to begin production of the car at its Maruti Suzuki plant in Gujarat by March-April. Sales of the car may begin in the summer of 2025 in Europe, India, and Japan.</p>', '', '5:36', 'V', NULL, 'en', 0, 0, 0, 0, 'A', '2024-11-20 10:22:37', '2024-11-20 10:22:37', '2024-11-20 10:22:37', 0, 0, 0, 0),
(3410, 'TlepiYMeeaE', NULL, 'EV News Bulletin| हिंदी ईवी समाचार बुलेटिन|', 2, '', NULL, '', 0, '<p><strong>EV News Bulletin| हिंदी ईवी समाचार बुलेटिन|</strong> सुजुकी मोटर कॉर्प ने अपनी पहली इलेक्ट्रिक कार \"ई-विटारा\" पेश की है। कंपनी की योजना है कि मार्च-अप्रैल में गुजरात के मारुति सुजुकी प्लांट में इसका उत्पादन शुरू किया जाए। इस कार की बिक्री 2025 की गर्मियों में यूरोप, भारत और जापान में शुरू हो सकती है।</p>', '', '5:36', 'V', NULL, 'hi', 0, 0, 0, 0, 'A', '2024-11-20 10:26:56', '2024-11-20 10:26:56', '2024-11-20 10:26:56', 0, 0, 0, 0);
